package com.example.biometricauth

import android.content.Context
import android.content.Intent
import android.content.SharedPreferences
import android.os.Bundle
import android.widget.Button
import android.widget.EditText
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat

object AuthPrefs {
    private const val PREF_NAME = "auth_prefs"
    private const val KEY_AUTHENTICATED = "authenticated"

    private fun prefs(context: Context): SharedPreferences {
        return context.getSharedPreferences(PREF_NAME, Context.MODE_PRIVATE)
    }

    fun isAuthenticated(context: Context): Boolean {
        return prefs(context).getBoolean(KEY_AUTHENTICATED, false)
    }

    fun setAuthenticated(context: Context, value: Boolean) {
        prefs(context).edit().putBoolean(KEY_AUTHENTICATED, value).apply()
    }

    fun clear(context: Context) {
        prefs(context).edit().clear().apply()
    }
}

class LauncherActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        if (AuthPrefs.isAuthenticated(this)) {
            startActivity(Intent(this, HomeActivity::class.java))
        } else {
            startActivity(Intent(this, LoginActivity::class.java))
        }
        finish()
    }
}

class LoginActivity : AppCompatActivity() {

    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo

    private lateinit var etPassword: EditText
    private lateinit var btnPasswordLogin: Button
    private lateinit var btnBiometricLogin: Button

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_login)

        etPassword = findViewById(R.id.etPassword)
        btnPasswordLogin = findViewById(R.id.btnPasswordLogin)
        btnBiometricLogin = findViewById(R.id.btnBiometricLogin)

        setupBiometric()
        setupPasswordFallback()
        updateBiometricAvailability()

        if (savedInstanceState == null && canAuthenticate()) {
            btnBiometricLogin.post {
                biometricPrompt.authenticate(promptInfo)
            }
        }
    }

    override fun onStart() {
        super.onStart()
        if (AuthPrefs.isAuthenticated(this)) {
            navigateToHome()
        }
    }

    private fun setupBiometric() {
        val executor = ContextCompat.getMainExecutor(this)
        biometricPrompt = BiometricPrompt(
            this,
            executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    AuthPrefs.setAuthenticated(this@LoginActivity, true)
                    Toast.makeText(
                        this@LoginActivity,
                        "Fingerprint verified successfully",
                        Toast.LENGTH_SHORT
                    ).show()
                    navigateToHome()
                }

                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    Toast.makeText(
                        this@LoginActivity,
                        "Biometric unavailable. Use your password.",
                        Toast.LENGTH_SHORT
                    ).show()
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    Toast.makeText(
                        this@LoginActivity,
                        "Fingerprint not recognized. Try again or use password.",
                        Toast.LENGTH_SHORT
                    ).show()
                }
            }
        )

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Quick Sign In")
            .setSubtitle("Use your fingerprint to continue")
            .setDescription("Fast and secure access")
            .setNegativeButtonText("Use Password")
            .build()
    }

    private fun setupPasswordFallback() {
        btnPasswordLogin.setOnClickListener {
            val password = etPassword.text?.toString()?.trim().orEmpty()
            if (isPasswordValid(password)) {
                AuthPrefs.setAuthenticated(this, true)
                Toast.makeText(this, "Logged in successfully", Toast.LENGTH_SHORT).show()
                navigateToHome()
            } else {
                Toast.makeText(this, "Enter a valid password", Toast.LENGTH_SHORT).show()
            }
        }

        btnBiometricLogin.setOnClickListener {
            if (canAuthenticate()) {
                biometricPrompt.authenticate(promptInfo)
            } else {
                Toast.makeText(this, "Biometric login not available. Use password.", Toast.LENGTH_SHORT).show()
            }
        }
    }

    private fun canAuthenticate(): Boolean {
        val biometricManager = BiometricManager.from(this)
        return biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG) ==
            BiometricManager.BIOMETRIC_SUCCESS
    }

    private fun updateBiometricAvailability() {
        btnBiometricLogin.isEnabled = canAuthenticate()
    }

    private fun isPasswordValid(password: String): Boolean {
        return password == "1234"
    }

    private fun navigateToHome() {
        startActivity(Intent(this, HomeActivity::class.java))
        finish()
    }
}

class HomeActivity : AppCompatActivity() {

    private lateinit var btnLogout: Button

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_home)

        btnLogout = findViewById(R.id.btnLogout)
        btnLogout.setOnClickListener {
            AuthPrefs.clear(this)
            startActivity(Intent(this, LoginActivity::class.java))
            finish()
        }
    }
}